import{_ as o,o as r,c as d,ag as l}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"圣经","description":"","frontmatter":{"title":"圣经"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/bible.md","filePath":"novels/jin-gu-yao/behind-the-scenes/bible.md","lastUpdated":1773897450000}'),a={name:"novels/jin-gu-yao/behind-the-scenes/bible.md"};function i(n,t,s,u,e,q){return r(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="圣经-—-故事核心设定文件" tabindex="-1">圣经 — 故事核心设定文件 <a class="header-anchor" href="#圣经-—-故事核心设定文件" aria-label="Permalink to &quot;圣经 — 故事核心设定文件&quot;">​</a></h1><blockquote><p>此文件是小说的&quot;单一事实来源&quot;。所有章节必须与此文件一致。 每写完一章后更新此文件。</p></blockquote><hr><h2 id="一、人物谱" tabindex="-1">一、人物谱 <a class="header-anchor" href="#一、人物谱" aria-label="Permalink to &quot;一、人物谱&quot;">​</a></h2><h3 id="主要人物" tabindex="-1">主要人物 <a class="header-anchor" href="#主要人物" aria-label="Permalink to &quot;主要人物&quot;">​</a></h3><h4 id="李三娘-平阳昭公主" tabindex="-1">李三娘（平阳昭公主） <a class="header-anchor" href="#李三娘-平阳昭公主" aria-label="Permalink to &quot;李三娘（平阳昭公主）&quot;">​</a></h4><ul><li><strong>称呼</strong>：三娘（家人）、李公子（女扮男装时）、公主（部下、后期）</li><li><strong>年龄</strong>：起兵时约22-25岁（推测，史无明确记载）</li><li><strong>性格关键词</strong>：果断、内敛、有大局观、偶有毒舌、不善表达情感但内心炽热</li><li><strong>核心矛盾</strong>：贵族身份 vs 起义领袖 / 将军 vs 母亲 / 忠于父亲大业 vs 自我意志</li><li><strong>外貌</strong>：待定（不过分描写美貌，重点是气质和眼神）</li><li><strong>口头禅/说话特点</strong>：简洁，不啰嗦，偶尔冒出让人意外的话</li></ul><h4 id="柴绍" tabindex="-1">柴绍 <a class="header-anchor" href="#柴绍" aria-label="Permalink to &quot;柴绍&quot;">​</a></h4><ul><li><strong>称呼</strong>：柴绍、驸马、嗣昌（字）</li><li><strong>性格关键词</strong>：勇猛、直率、有点大大咧咧、深爱三娘但不善言辞</li><li><strong>核心矛盾</strong>：作为丈夫的愧疚（把妻子留在险地）/ 发现妻子比自己更能打的复杂情感</li><li><strong>特点</strong>：将门之后，身手了得，但在政治谋略上不如三娘</li></ul><h4 id="马三宝" tabindex="-1">马三宝 <a class="header-anchor" href="#马三宝" aria-label="Permalink to &quot;马三宝&quot;">​</a></h4><ul><li><strong>称呼</strong>：三宝、马三宝</li><li><strong>身份</strong>：三娘的家僮（家仆），后成为心腹</li><li><strong>性格关键词</strong>：机灵、话多、忠诚、胆大包天、有市井智慧</li><li><strong>角色定位</strong>：半个叙事者/旁观者，提供幽默和地气，是读者的&quot;眼睛&quot;</li><li><strong>说话特点</strong>：话多，爱碎念，偶尔冒出惊人之语</li><li><strong>忠诚根源</strong>：八岁被赌鬼父亲卖给西市屠户当学徒，被打了四年。十二岁逃跑被抓，当街扒衣被打，半条街围观。十三四岁的三娘让管家花三贯钱把他买下来。关键不是买——进柴府第一天三娘问他&quot;你叫什么名字？&quot;在屠户那里四年，没人问过。第二天厨房多了一罐药膏，&quot;少夫人让放的&quot;。手腕有秤钩旧疤，袖子永远拉得很低。忠诚的根不是感恩，是恐惧+存在：离开三娘他就不是&quot;马三宝&quot;了，会回到那个没有名字的崽子。→ &quot;十二岁那年的三贯钱，这辈子还不清。那句&#39;你叫什么名字&#39;，这辈子还不清。&quot;</li></ul><h4 id="何潘仁" tabindex="-1">何潘仁 <a class="header-anchor" href="#何潘仁" aria-label="Permalink to &quot;何潘仁&quot;">​</a></h4><ul><li><strong>称呼</strong>：何大、何潘仁</li><li><strong>身份</strong>：粟特人，康国出身，十四岁出走，十六岁到长安，做了十年胡商，大业七年被打二十板子后走上反叛之路</li><li><strong>性格关键词</strong>：愤怒、危险、精明、粗犷、有胡人的豪爽但底色是恨</li><li><strong>核心创伤</strong>：大业七年朝廷征马，衙差打了他二十板子，说&quot;胡狗也配讲条件&quot;。当天下午衙差抄了他马厩，妻子冲出去拦被推倒，后脑磕石头。没死但脑伤，半年后走到河边——不知失足还是什么。埋在长安城外荒地，胡人无资格葬城内。妻子名：阿史那·月。他去告状，衙差是县尉小舅子，状子被截。从二十板子到失去一切，是完整的毁灭链</li><li><strong>核心矛盾</strong>：他聚兵不只是为了吃饭，是为了报复和痛苦。他打汉人村子的时候想的是二十板子和妻子在河边的背影。但仇打不完——他知道这一点，却停不下来</li><li><strong>关键物件</strong>：帐篷墙上挂着一把隋军横刀——那个衙差的。帐篷柱子上挂着一个银坠子——妻子的。去年冬天碰到那个衙差在逃难，跪下磕头。他没杀——&quot;杀了他那二十板子还是在。我老婆还是在河里&quot;</li><li><strong>对三娘</strong>：来&quot;看看&quot;不是来归顺。带三十几骑，半看半示威。三娘不带刀让他意外——&quot;不怕我杀你？&quot;&quot;你要杀我不会来这儿。&quot;</li></ul><h4 id="李渊" tabindex="-1">李渊 <a class="header-anchor" href="#李渊" aria-label="Permalink to &quot;李渊&quot;">​</a></h4><ul><li><strong>角色</strong>：父亲 + 政治家，远在太原</li><li><strong>在故事中</strong>：主要通过书信和传闻出现，后期直接登场</li><li><strong>性格</strong>：深沉、有野心但善于隐藏、对三娘有真实的父女情</li></ul><h4 id="李世民" tabindex="-1">李世民 <a class="header-anchor" href="#李世民" aria-label="Permalink to &quot;李世民&quot;">​</a></h4><ul><li><strong>角色</strong>：弟弟，后期会师时登场</li><li><strong>性格</strong>：年轻、锐利、有枭雄之气</li><li><strong>与三娘的关系</strong>：姐弟间的默契和竞争</li></ul><h4 id="柴哲威" tabindex="-1">柴哲威 <a class="header-anchor" href="#柴哲威" aria-label="Permalink to &quot;柴哲威&quot;">​</a></h4><ul><li><strong>年龄</strong>：五岁（617年）</li><li><strong>性格</strong>：倔强、好胜、像爹——挺胸走路，仿佛石头会自动让开</li><li><strong>特征</strong>：自封&quot;男子汉&quot;，装大人，踩过牛粪，说过&quot;男人不会走路这么好看&quot;</li><li><strong>角色功能</strong>：无意间当了宣传员（&quot;我娘煮的粥可好喝了&quot;），制造喜剧，偶尔说出刺痛三娘的童言（&quot;那个小孩比令武还瘦&quot;）</li></ul><h4 id="柴令武" tabindex="-1">柴令武 <a class="header-anchor" href="#柴令武" aria-label="Permalink to &quot;柴令武&quot;">​</a></h4><ul><li><strong>年龄</strong>：三岁（617年）</li><li><strong>性格</strong>：爱哭、黏人、口水大王，嗓门大得像他爹</li><li><strong>特征</strong>：骑马三宝当马、拉屎有审美标准、到哪都要布老虎</li><li><strong>角色功能</strong>：三娘母性的锚点，制造混乱和温暖</li></ul><h3 id="次要人物-已出场" tabindex="-1">次要人物（已出场） <a class="header-anchor" href="#次要人物-已出场" aria-label="Permalink to &quot;次要人物（已出场）&quot;">​</a></h3><h4 id="赵大-原名赵铁柱-假名" tabindex="-1">赵大（原名赵铁柱，假名） <a class="header-anchor" href="#赵大-原名赵铁柱-假名" aria-label="Permalink to &quot;赵大（原名赵铁柱，假名）&quot;">​</a></h4><ul><li><strong>首次出场</strong>：第三章</li><li><strong>身份</strong>：隋军逃兵，六年从军经历（征高句丽→打瓦岗），娘子军第一个练兵教头</li><li><strong>性格</strong>：沉默、务实、&quot;管饭吗？&quot;型</li><li><strong>特征</strong>：当过兵的坐姿（腰板直、左手垂在大腿外侧），一眼看出三娘是女人</li></ul><h4 id="孙守道" tabindex="-1">孙守道 <a class="header-anchor" href="#孙守道" aria-label="Permalink to &quot;孙守道&quot;">​</a></h4><ul><li><strong>首次出场</strong>：第三章</li><li><strong>身份</strong>：前鄠县衙门账房，管了八年钱粮，被三娘任命为粮草管事</li><li><strong>性格</strong>：话多、好面子、精于数字</li><li><strong>特征</strong>：准备了一长串自我介绍但被三娘一句&quot;你管粮&quot;截断</li></ul><h4 id="老周" tabindex="-1">老周 <a class="header-anchor" href="#老周" aria-label="Permalink to &quot;老周&quot;">​</a></h4><ul><li><strong>身份</strong>：李氏庄园管事，一直在鄠县看守庄园</li><li><strong>特征</strong>：胆小、忠实、舀粥心疼粮食</li></ul><h4 id="刘管家" tabindex="-1">刘管家 <a class="header-anchor" href="#刘管家" aria-label="Permalink to &quot;刘管家&quot;">​</a></h4><ul><li><strong>身份</strong>：柴府管家，跟随三娘从长安到鄠县，路上负责打前站</li><li><strong>与老周的关系</strong>：刘管家是柴府带来的人，老周是庄园本地的人</li></ul><h4 id="鄠县县令-李孝常" tabindex="-1">鄠县县令（李孝常） <a class="header-anchor" href="#鄠县县令-李孝常" aria-label="Permalink to &quot;鄠县县令（李孝常）&quot;">​</a></h4><ul><li><strong>首次出场</strong>：第一章末尾（暗处视角）</li><li><strong>身份</strong>：鄠县县令，乱世中没有跑的官员</li><li><strong>性格</strong>：冷静、精于算计、蛇一样的耐心</li><li><strong>动机</strong>：赌注——如果能替长安留守抓住李渊的女儿，七品县令一步登天</li><li><strong>手段</strong>：信息战——派人渗透、收买眼线、记录动向、给长安写密报。不硬打，只盯</li><li><strong>角色定位</strong>：前五章暗线对手，第六七章浮出水面</li><li><strong>在文中的痕迹</strong>：第1章末灯下公文 / 第2章南门小吏当晚送报+老周说有人来问庄子 / 第3章数人头老汉 / 第4章路上扁担藏刀 / 第5章砍柴人</li></ul><h3 id="次要人物-未出场" tabindex="-1">次要人物（未出场） <a class="header-anchor" href="#次要人物-未出场" aria-label="Permalink to &quot;次要人物（未出场）&quot;">​</a></h3><ul><li><strong>李仲文</strong> — 归附义军首领之一，待展开</li><li><strong>向善志</strong> — 归附义军首领之一，待展开</li><li><strong>丘师利</strong> — 归附义军首领之一，待展开</li><li><strong>窦皇后</strong>（已故）— 三娘的母亲，可通过回忆出现</li><li><strong>李建成</strong> — 大哥，可能在后期出现</li></ul><hr><h2 id="二、时间线" tabindex="-1">二、时间线 <a class="header-anchor" href="#二、时间线" aria-label="Permalink to &quot;二、时间线&quot;">​</a></h2><h3 id="已写章节覆盖的时间" tabindex="-1">已写章节覆盖的时间 <a class="header-anchor" href="#已写章节覆盖的时间" aria-label="Permalink to &quot;已写章节覆盖的时间&quot;">​</a></h3><ul><li>第1章：617年五月十五日 — 五月十八日（柴府→离长安）</li><li>第2章：617年五月十八日（长安→鄠县，一天行程）</li><li>第3章：617年五月下旬-六月初（开仓10天，招到300人）</li><li>第5章：617年六月中旬（何潘仁来谈→归顺→大军到→筹粮）</li></ul><h3 id="全局时间线" tabindex="-1">全局时间线 <a class="header-anchor" href="#全局时间线" aria-label="Permalink to &quot;全局时间线&quot;">​</a></h3><ul><li><strong>大业十三年（617年）五月</strong> — 李渊决定起兵</li><li><strong>617年五月</strong> — 柴绍离开长安赴太原，三娘独留</li><li><strong>617年五月-六月</strong> — 三娘回鄠县庄园，散财招兵</li><li><strong>617年六月-八月</strong> — 收编各路义军，攻占数县</li><li><strong>617年九月</strong> — 李渊渡河入关中</li><li><strong>617年九月</strong> — 柴绍带骑兵迎接三娘</li><li><strong>617年九-十一月</strong> — 与李世民会师渭北，共克长安</li><li><strong>618-623年</strong> — 驻守娘子关（此段自由度最大）</li><li><strong>武德六年（623年）二月</strong> — 三娘去世，军礼下葬</li></ul><hr><h2 id="三、已埋伏笔" tabindex="-1">三、已埋伏笔 <a class="header-anchor" href="#三、已埋伏笔" aria-label="Permalink to &quot;三、已埋伏笔&quot;">​</a></h2><p>（随写作更新）</p><table tabindex="0"><thead><tr><th>埋设章节</th><th>伏笔内容</th><th>预计收回章节</th><th>状态</th></tr></thead><tbody><tr><td>第1章</td><td>缝了一半的旧袍（&quot;等你回来再说&quot;）</td><td>第13章（重逢）</td><td>待收</td></tr><tr><td>第1章</td><td>令武画的画（四个圈+&quot;家&quot;字）</td><td>待定</td><td>待收</td></tr><tr><td>第1章</td><td>柴绍嘿嘿笑的憨样</td><td>第13章（重逢对比）</td><td>待收</td></tr><tr><td>第1章</td><td>木马断了/马三宝削木马</td><td>贯穿，到第3章仍在用</td><td>持续</td></tr><tr><td>第2章</td><td>&quot;那个小孩比令武还瘦&quot;</td><td>第2章末→第3章开仓决策</td><td>✅ 已收</td></tr><tr><td>第2章</td><td>&quot;这些田地，种的出粮。这些人，打得了仗。&quot;</td><td>第3章兑现</td><td>✅ 已收</td></tr><tr><td>第3章</td><td>三娘的小册子（情报记录习惯）</td><td>贯穿全书</td><td>持续</td></tr><tr><td>第3章</td><td>&quot;三宝，把快马喂饱，你可能要出趟远门&quot;</td><td>第4章（出使何潘仁）</td><td>待收</td></tr><tr><td>第3章</td><td>何潘仁的手下来探</td><td>第4章</td><td>✅ 已收</td></tr><tr><td>第3章</td><td>粮食只够30-50天</td><td>第5-6章（粮食危机）</td><td>待收</td></tr><tr><td>第2章</td><td>鄠县小吏记了一笔（值守簿）</td><td>第6-7章（县令追查）</td><td>待收</td></tr><tr><td>第4章</td><td>何潘仁的二十板子/&quot;胡狗&quot;</td><td>贯穿（他的核心驱动力）</td><td>持续</td></tr><tr><td>第4章</td><td>衙差的横刀挂在墙上</td><td>待定（可能在何潘仁归顺时摘下）</td><td>待收</td></tr><tr><td>第4章</td><td>何潘仁&quot;看看，不是答应&quot;</td><td>第5章（正面谈判）</td><td>✅ 已收</td></tr><tr><td>第4章</td><td>马三宝十二岁偷饼被救</td><td>贯穿（忠诚的根）</td><td>持续</td></tr><tr><td>第4章</td><td>&quot;要么她疯了，要么她比所有男人都狠&quot;</td><td>后续何潘仁对三娘的态度</td><td>持续</td></tr><tr><td>第5章</td><td>何潘仁条件：&quot;二十板子&quot;作为军纪惩罚数</td><td>第6章（军法考验）</td><td>待收</td></tr><tr><td>第5章</td><td>何潘仁要&quot;写在碑上的名字&quot;</td><td>第21章或结局</td><td>待收</td></tr><tr><td>第5章</td><td>粟特握手礼（掌心朝上）</td><td>重逢/告别场景</td><td>待收</td></tr><tr><td>第5章</td><td>小册子新页：鄠县县令+问号</td><td>第6-7章</td><td>待收</td></tr><tr><td>第5章</td><td>三娘深夜叫&quot;嗣昌&quot;（柴绍的字）</td><td>第13章（重逢）</td><td>待收</td></tr><tr><td>第5章</td><td>筹粮一箭三雕（赵大穿胡甲+孙守道出面）</td><td>第6章（粮到/大户反应）</td><td>待收</td></tr><tr><td>第5章</td><td>三娘说&quot;何潘仁的人很饿，我管不了多久&quot;</td><td>后续（她用恐惧但不说谎）</td><td>持续</td></tr></tbody></table><hr><h2 id="四、已出现地名" tabindex="-1">四、已出现地名 <a class="header-anchor" href="#四、已出现地名" aria-label="Permalink to &quot;四、已出现地名&quot;">​</a></h2><p>（随写作更新）</p><table tabindex="0"><thead><tr><th>地名</th><th>首次出现章节</th><th>描写要点</th></tr></thead><tbody><tr><td>长安柴府</td><td>第1章</td><td>后院有槐树，角门出入，有铜镜</td></tr><tr><td>长安城</td><td>第1章</td><td>一百零九坊，坊门宵禁，暮鼓</td></tr><tr><td>鄠县</td><td>第2章</td><td>终南山脚下，距长安约40公里（一天路程），麦田</td></tr><tr><td>李氏庄园</td><td>第2-3章</td><td>三娘娘家产业，有粮仓（约1200石），管事老周</td></tr><tr><td>终南山</td><td>第2章</td><td>山脊线像深青色长蛇，是长安和鄠县之间的屏障</td></tr><tr><td>鄠县县城南门</td><td>第2章</td><td>小吏值守处，三娘经过时被记录</td></tr><tr><td>何潘仁营地</td><td>第4章</td><td>终南山余脉中，像放大100倍的西市，乱但有草莽秩序</td></tr></tbody></table><hr><h2 id="五、世界观设定" tabindex="-1">五、世界观设定 <a class="header-anchor" href="#五、世界观设定" aria-label="Permalink to &quot;五、世界观设定&quot;">​</a></h2><h3 id="时代感" tabindex="-1">时代感 <a class="header-anchor" href="#时代感" aria-label="Permalink to &quot;时代感&quot;">​</a></h3><ul><li>隋末乱世，社会秩序崩溃</li><li>流民遍地，盗匪横行</li><li>关中相对稳定但暗流涌动</li><li>各地豪强割据，谁都可能成事</li></ul><h3 id="军事设定" tabindex="-1">军事设定 <a class="header-anchor" href="#军事设定" aria-label="Permalink to &quot;军事设定&quot;">​</a></h3><ul><li>义军 ≠ 正规军，装备参差不齐</li><li>三娘的军纪是她能脱颖而出的关键（&quot;禁兵无得侵掠&quot;）</li><li>娘子军的组成：庄园佃农 + 山中亡命之徒 + 收编的各路义军</li></ul><h3 id="社会设定" tabindex="-1">社会设定 <a class="header-anchor" href="#社会设定" aria-label="Permalink to &quot;社会设定&quot;">​</a></h3><ul><li>隋代女性地位相对较高（受北朝胡风影响）</li><li>但女性统兵仍然是异数</li><li>胡汉杂居，文化多元</li></ul><hr><h2 id="六、每章摘要" tabindex="-1">六、每章摘要 <a class="header-anchor" href="#六、每章摘要" aria-label="Permalink to &quot;六、每章摘要&quot;">​</a></h2><p>（写完每章后在此更新）</p><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>时间</th><th>核心事件</th><th>字数</th></tr></thead><tbody><tr><td>第1章</td><td>长安夜</td><td>617年五月十五-十八</td><td>柴绍带来密信→离开→三娘决定带娃出走→换男装</td><td>~4000</td></tr><tr><td>第2章</td><td>南山路</td><td>617年五月十八</td><td>带娃赶路→路见饥民→到达庄园→决定开仓</td><td>~4000</td></tr><tr><td>第3章</td><td>开仓</td><td>617年五月下旬-六月初</td><td>散粥招人→收赵大练兵→收孙守道管粮→何潘仁来探</td><td>~4200</td></tr><tr><td>第4章</td><td>狐与虎</td><td>617年六月</td><td>马三宝单骑出使何潘仁→游说成功→何潘仁来见三娘</td><td>~4400</td></tr><tr><td>第5章</td><td>名分</td><td>617年六月中旬</td><td>三娘与何潘仁正面谈判→商人式协议→何潘仁归顺→大军到达→筹粮一箭三雕→鄠县县令暗线</td><td>~4500</td></tr></tbody></table><h3 id="每章灵魂细节-压缩后恢复记忆用" tabindex="-1">每章灵魂细节（压缩后恢复记忆用） <a class="header-anchor" href="#每章灵魂细节-压缩后恢复记忆用" aria-label="Permalink to &quot;每章灵魂细节（压缩后恢复记忆用）&quot;">​</a></h3><p><strong>第1章</strong>：瘸腿兔子的笑话 / 木马断了兄弟大战 / 柴绍&quot;同时踩到金子和蛇&quot;的表情 / &quot;男人嘛&quot; / 令武画的画（四个圈+&quot;家&quot;字）/ 柴哲威&quot;男人不会走路这么好看&quot; / 令武把口水流到三娘肩膀上</p><p><strong>第2章</strong>：令武骑马三宝当马喊&quot;驾驾&quot; / 柴哲威踩牛粪 / 令武拉屎系统工程 / &quot;那个小孩比令武还瘦&quot;→三娘开始&quot;算账&quot; / &quot;这些田地种的出粮，这些人打得了仗&quot; / 三娘先给孩子洗手吃饭，然后才去开粮仓 / 令武梦话&quot;驾驾&quot; / <strong>鄠县小吏值守簿记了一行字→十天后送到县令案头</strong></p><p><strong>第3章</strong>：柴哲威&quot;我娘煮的粥可好喝了&quot;传遍鄠县 / 赵大（赵铁柱）的兵坐姿暴露身份 / &quot;管饭吗？&quot;&quot;管。&quot; / 赵大心想&quot;一个女人抱着娃要造反，管他呢至少粥是稠的&quot; / 孙守道自我介绍被&quot;你管粮&quot;截断 / 三娘的小册子早写了何潘仁 / 令武从墙头掉下来马三宝接住是&quot;日常操作&quot; / <strong>孙守道算账：粮食最多撑30-50天→&quot;怨比饿好&quot;</strong></p><p><strong>第4章</strong>：马三宝要&quot;遗书存放地&quot;（假装开玩笑，笑容很僵）/ 三娘&quot;你怕吗？&quot;&quot;怕。&quot;&quot;那你还去？&quot; / <strong>马三宝十二岁偷饼被救的回忆</strong> / 三娘&quot;你卖饼会先问他饿不饿&quot; / 营地像放大100倍的西市 / 汉人被踢无人在意 / 波斯地毯当标志沾了泥 / 横刀下面的暗色斑 / <strong>何潘仁拔刀架马三宝脖子：&quot;再说一遍&quot;</strong> / <strong>&quot;胡狗也配讲条件？二十板子&quot;</strong> / &quot;每打一个村子我就想一次那二十板子&quot; / 衙差的横刀故事：&quot;杀了他那二十板子还是在&quot; / &quot;从胡匪变将军，从贼变人&quot; / <strong>&quot;看看，不是答应&quot;</strong> / &quot;她是猎人&quot; / &quot;要么她疯了，要么她比所有男人都狠&quot; / 三娘不带刀→&quot;不怕我杀你？&quot;&quot;你要杀我不会来这儿&quot; / 令武哭着要骑大马→何潘仁肩膀微动 / 马三宝的手一直在抖 / <strong>&quot;十二岁那年的饼，这辈子还不清&quot;</strong></p><p><strong>第5章</strong>：何潘仁不喝粥（戒备）/ 三十六骑散开自动避死角 / 三娘直击要害：&quot;你不是在打天下，你是在跑&quot; / 二十板子再次出现→&quot;疼的不是背，疼的是你十年&quot; / <strong>何潘仁条件①：犯军纪打不杀，&quot;二十板子&quot;（数字回响）</strong> / <strong>何潘仁条件②：要一个写在碑上的名字——&quot;是一个人&quot;</strong>（三娘替他说完）/ 粟特握手礼：右手掌心朝上 / 三娘谈判后蹲在院中肩膀发抖（绷久了松了）/ 马三宝偷听被发现（脚露在门槛外）/ 孙守道粮食危机：九百石够十八天 / <strong>筹粮一箭三雕</strong>：赵大穿何潘仁的甲+孙守道出面→给恐惧+给面子+给台阶 / 三娘&quot;他们不借就是抗命&quot;&quot;何潘仁的人很饿，我管不了多久&quot; / 三娘深夜看孩子→给哲威盖被→摸令武额头 / <strong>旧袍再次出现</strong>→&quot;嗣昌&quot;（柴绍的字，第一次叫出来）/ <strong>小册子新页：鄠县县令+问号</strong>→暗线铺垫 / 灯油也要算（细节）</p>',66)])])}const b=o(a,[["render",i]]);export{g as __pageData,b as default};
